question.template:
import contextlib
import io
import json
import re

student_code = """{{ STUDENT_ANSWER | e('py') }}"""
rows = [["Check", "Expected", "Got", "Comment", "Mark", "iscorrect"]]
total_awarded = 0.0

def compact(value):
    text = str(value)
    if len(text) > 240:
        return text[:237] + "..."
    return text

def cleaned_lines(text):
    return [line.rstrip() for line in text.splitlines() if line.strip()]

def add_result(label, expected, got, comment, awarded, mark, iscorrect):
    global total_awarded
    total_awarded += awarded
    rows.append([label, compact(expected), compact(got), comment, f"{awarded:.1f}/{mark:.1f}", iscorrect])

def require_callable(namespace, name):
    obj = namespace.get(name)
    if not callable(obj):
        raise NameError(f"Function '{name}' is missing or not callable.")
    return obj

def sanitize(code):
    code = re.sub(r"def\s+setup_application\(", "def run_classifier_pipeline(", code)
    code = code.replace("setup_application(", "run_classifier_pipeline(")
    code = re.sub(r"correct\s*=\s*<\s*your_code\s*>", "correct=0", code)
    code = re.sub(r"total\s*=\s*<\s*your_code\s*>", "total=0", code)
    code = re.sub(r"threshold\s*=\s*<\s*your_code\s*>", "threshold=2.0", code)
    code = re.sub(r"print_each\s*=\s*<\s*your_code\s*>", "print_each=True", code)
    return code

def load_namespace():
    hidden_support = """
def make_print_status(status_text):
    pass

def run_classifier_pipeline(*args, **kwargs):
    return 7, 0, 7, ["setosa"], 100.0

def print_summary(*args, **kwargs):
    pass
"""
    code = hidden_support + "\n" + sanitize(student_code)
    compiled = compile(code, "<student>", "exec")
    namespace = {"__name__": "student_submission"}
    with contextlib.redirect_stdout(io.StringIO()):
        exec(compiled, namespace)
    return namespace

DEFAULT_GRADE = 1.0

try:
    namespace = load_namespace()
    status = []
    pipeline_calls = []
    namespace["make_print_status"] = lambda text: status.append(text)
    namespace["run_classifier_pipeline"] = lambda *args, **kwargs: (pipeline_calls.append((args, kwargs)) or (7, 0, 7, ["setosa"], 100.0))
    namespace["print_summary"] = lambda *args: None
    require_callable(namespace, "main")()
    success = ("Keyword override run" in status) and any(args == () and kwargs == {"threshold": 1.8, "print_each": False} for args, kwargs in pipeline_calls)
    add_result("Task 7", "main() calls run_classifier_pipeline(threshold=1.8, print_each=False)", {"status": status, "pipeline_calls": pipeline_calls}, "The keyword override block should use the named parameters exactly as shown.", 1.0 if success else 0.0, 1.0, 1 if success else 0)
except Exception as exc:
    add_result("Task 7", "Keyword override block works", f"{type(exc).__name__}: {exc}", "The code could not be imported or run for Task 7.", 0.0, 1.0, 0)

print(json.dumps({
    "fraction": total_awarded / DEFAULT_GRADE,
    "testresults": rows,
}))
